package strategies

import "fmt"

type PricingStrategy interface {
	CalculatePrice(basePrice float64, context PricingContext) float64
	GetName() string
}

type PricingContext struct {
	UserID          string
	ItemCount       int
	MembershipLevel string
	IsFirstPurchase bool
	CartTotal       float64
}

type VolumeDiscountStrategy struct{}

func (v *VolumeDiscountStrategy) GetName() string {
	return "Volume Discount"
}

func (v *VolumeDiscountStrategy) CalculatePrice(basePrice float64, ctx PricingContext) float64 {
	if ctx.ItemCount >= 10 {
		return basePrice * 0.8
	}
	if ctx.ItemCount >= 5 {
		return basePrice * 0.9
	}
	return basePrice
}

type MembershipDiscountStrategy struct{}

func (m *MembershipDiscountStrategy) GetName() string {
	return "Membership Discount"
}

func (m *MembershipDiscountStrategy) CalculatePrice(basePrice float64, ctx PricingContext) float64 {
	switch ctx.MembershipLevel {
	case "vip":
		return basePrice * 0.7
	case "premium":
		return basePrice * 0.85
	default:
		return basePrice
	}
}

type NewUserDiscountStrategy struct{}

func (n *NewUserDiscountStrategy) GetName() string {
	return "New User Discount"
}

func (n *NewUserDiscountStrategy) CalculatePrice(basePrice float64, ctx PricingContext) float64 {
	if ctx.IsFirstPurchase {
		return basePrice * 0.9
	}
	return basePrice
}

type PricingEngine struct {
	strategies []PricingStrategy
}

func NewPricingEngine() *PricingEngine {
	return &PricingEngine{}
}

func (pe *PricingEngine) AddStrategy(s PricingStrategy) {
	pe.strategies = append(pe.strategies, s)
}

func (pe *PricingEngine) CalculateFinalPrice(basePrice float64, ctx PricingContext) float64 {
	finalPrice := basePrice
	for _, strategy := range pe.strategies {
		finalPrice = strategy.CalculatePrice(finalPrice, ctx)
	}
	if finalPrice < 0 {
		return 0
	}
	return finalPrice
}

func main() {
	engine := NewPricingEngine()
	engine.AddStrategy(&VolumeDiscountStrategy{})
	engine.AddStrategy(&MembershipDiscountStrategy{})
	engine.AddStrategy(&NewUserDiscountStrategy{})

	ctx := PricingContext{
		UserID:          "user123",
		ItemCount:       7,
		MembershipLevel: "premium",
		IsFirstPurchase: true,
		CartTotal:       100.0,
	}

	price := engine.CalculateFinalPrice(100.0, ctx)
	fmt.Printf("Final price: $%.2f\n", price)
}

package options

import (
	"fmt"
	"time"
)

type Server struct {
	Host         string
	Port         int
	Timeout      time.Duration
	MaxConnections int
	Logger       Logger
	Middleware   []Middleware
}

type Logger interface {
	Info(msg string, args ...interface{})
	Error(msg string, args ...interface{})
}

type Middleware func(handler http.Handler) http.Handler

type Option func(*Server)

func WithHost(host string) Option {
	return func(s *Server) {
		s.Host = host
	}
}

func WithPort(port int) Option {
	return func(s *Server) {
		s.Port = port
	}
}

func WithTimeout(timeout time.Duration) Option {
	return func(s *Server) {
		s.Timeout = timeout
	}
}

func WithMaxConnections(max int) Option {
	return func(s *Server) {
		s.MaxConnections = max
	}
}

func WithLogger(logger Logger) Option {
	return func(s *Server) {
		s.Logger = logger
	}
}

func WithMiddleware(mw Middleware) Option {
	return func(s *Server) {
		s.Middleware = append(s.Middleware, mw)
	}
}

func NewServer(opts ...Option) *Server {
	s := &Server{
		Host:         "localhost",
		Port:         8080,
		Timeout:      30 * time.Second,
		MaxConnections: 100,
		Logger:       DefaultLogger{},
	}

	for _, opt := range opts {
		opt(s)
	}

	return s
}

type DefaultLogger struct{}

func (d DefaultLogger) Info(msg string, args ...interface{}) {
	fmt.Printf("[INFO] "+msg+"\n", args...)
}

func (d DefaultLogger) Error(msg string, args ...interface{}) {
	fmt.Printf("[ERROR] "+msg+"\n", args...)
}

func main() {
	server := NewServer(
		WithHost("0.0.0.0"),
		WithPort(9090),
		WithTimeout(60*time.Second),
		WithMaxConnections(500),
	)

	fmt.Printf("Server configured: %s:%d\n", server.Host, server.Port)
}

package observer

import (
	"fmt"
	"sync"
)

type Event struct {
	Type      string
	Payload   interface{}
	Timestamp int64
}

type EventBus struct {
	mu       sync.RWMutex
	subscribers map[string][]chan Event
}

func NewEventBus() *EventBus {
	return &EventBus{
		subscribers: make(map[string][]chan Event),
	}
}

func (eb *EventBus) Subscribe(eventType string, bufferSize int) chan Event {
	eb.mu.Lock()
	defer eb.mu.Unlock()

	ch := make(chan Event, bufferSize)
	eb.subscribers[eventType] = append(eb.subscribers[eventType], ch)
	return ch
}

func (eb *EventBus) Unsubscribe(eventType string, ch chan Event) {
	eb.mu.Lock()
	defer eb.mu.Unlock()

	subs := eb.subscribers[eventType]
	for i, sub := range subs {
		if sub == ch {
			eb.subscribers[eventType] = append(subs[:i], subs[i+1:]...)
			close(ch)
			break
		}
	}
}

func (eb *EventBus) Publish(event Event) {
	eb.mu.RLock()
	defer eb.mu.RUnlock()

	subs := eb.subscribers[event.Type]
	for _, ch := range subs {
		select {
		case ch <- event:
		default:
			fmt.Printf("Warning: subscriber channel full for event %s\n", event.Type)
		}
	}
}

func main() {
	ebus := NewEventBus()

	userCh := ebus.Subscribe("user.created", 10)
	orderCh := ebus.Subscribe("order.created", 10)

	go func() {
		for event := range userCh {
			fmt.Printf("User event: %+v\n", event.Payload)
		}
	}()

	go func() {
		for event := range orderCh {
			fmt.Printf("Order event: %+v\n", event.Payload)
		}
	}()

	ebus.Publish(Event{Type: "user.created", Payload: "Alice"})
	ebus.Publish(Event{Type: "order.created", Payload: "ORD-123"})
}

package pool

import (
	"bytes"
	"sync"
)

type BufferPool struct {
	pool sync.Pool
}

func NewBufferPool() *BufferPool {
	return &BufferPool{
		pool: sync.Pool{
			New: func() interface{} {
				return bytes.NewBuffer(make([]byte, 0, 1024))
			},
			},
		}
}

func (bp *BufferPool) Get() *bytes.Buffer {
	buf := bp.pool.Get().(*bytes.Buffer)
	buf.Reset()
	return buf
}

func (bp *BufferPool) Put(buf *bytes.Buffer) {
	bp.pool.Put(buf)
}

func (bp *BufferPool) ProcessRequest(data []byte) ([]byte, error) {
	buf := bp.Get()
	defer bp.Put(buf)

	buf.Write(data)
	buf.WriteString("\n")
	buf.WriteString("processed")

	result := make([]byte, buf.Len())
	copy(result, buf.Bytes())
	return result, nil
}

func main() {
	bp := NewBufferPool()

	// Simulate concurrent requests
	var wg sync.WaitGroup
	for i := 0; i < 1000; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			data := []byte(fmt.Sprintf("request-%d", id))
			result, err := bp.ProcessRequest(data)
			if err != nil {
				fmt.Println(err)
				return
			}
			fmt.Printf("Processed: %s\n", string(result))
		}(i)
	}
	wg.Wait()
}

package middleware

import (
	"fmt"
	"log"
	"net/http"
	"time"
)

type HandlerFunc func(http.ResponseWriter, *http.Request) (*http.Response, error)

type Middleware func(HandlerFunc) HandlerFunc

func LoggingMiddleware(next HandlerFunc) HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) (*http.Response, error) {
		start := time.Now()
		log.Printf("Started %s %s", r.Method, r.URL.Path)

		resp, err := next(w, r)

		duration := time.Since(start)
		log.Printf("Completed %s %s in %v", r.Method, r.URL.Path, duration)

		return resp, err
	}
}

func AuthMiddleware(next HandlerFunc) HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) (*http.Response, error) {
		token := r.Header.Get("Authorization")
		if token == "" {
			return nil, fmt.Errorf("missing authorization header")
		}

		if !validateToken(token) {
			return nil, fmt.Errorf("invalid token")
		}

		return next(w, r)
	}
}

func RateLimitMiddleware(next HandlerFunc) HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) (*http.Response, error) {
		if isRateLimited(r.RemoteAddr) {
			return nil, fmt.Errorf("rate limit exceeded")
		}

		return next(w, r)
	}
}

func Compose(middlewares ...Middleware) Middleware {
	return func(next HandlerFunc) HandlerFunc {
		for i := len(middlewares) - 1; i >= 0; i-- {
			next = middlewares[i](next)
		}
		return next
	}
}

func validateToken(token string) bool {
	return len(token) > 10
}

func isRateLimited(ip string) bool {
	return false
}

func main() {
	chain := Compose(
		LoggingMiddleware,
		AuthMiddleware,
		RateLimitMiddleware,
	)

	handler := chain(func(w http.ResponseWriter, r *http.Request) (*http.Response, error) {
		fmt.Fprintf(w, "Hello, World!")
		return nil, nil
	})

	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}

package context

import (
	"context"
	"fmt"
	"time"
)

type Task struct {
	ID   string
	Data string
}

func RunTaskWithContext(ctx context.Context, task Task) error {
	// Simulate long-running work
	ticker := time.NewTicker(100 * time.Millisecond)
	defer ticker.Stop()

	for {
		select {
		case <-ctx.Done():
			fmt.Printf("Task %s cancelled: %v\n", task.ID, ctx.Err())
			return ctx.Err()
		case <-ticker.C:
			fmt.Printf("Task %s processing...\n", task.ID)
			// Check context periodically
			if isCancelled(ctx) {
				return fmt.Errorf("task %s manually cancelled", task.ID)
			}
		}
	}
}

func isCancelled(ctx context.Context) bool {
	select {
	case <-ctx.Done():
		return true
	default:
		return false
	}
}

func main() {
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	task := Task{ID: "task-1", Data: "process-data"}
	err := RunTaskWithContext(ctx, task)
	if err != nil {
		fmt.Printf("Task failed: %v\n", err)
	}

	// Demonstrate cancellation
	ctx2, cancel2 := context.WithCancel(context.Background())

	go func() {
		time.Sleep(500 * time.Millisecond)
		fmt.Println("Cancelling task...")
		cancel2()
	}()

	task2 := Task{ID: "task-2", Data: "another-task"}
	err2 := RunTaskWithContext(ctx2, task2)
	fmt.Printf("Task 2 result: %v\n", err2)
}

package builder

import (
	"fmt"
	"strings"
)

type DatabaseConfig struct {
	Host     string
	Port     int
	Database string
	Username string
	Password string
	SSL      bool
	Timeout  int
}

type ConfigBuilder struct {
	config DatabaseConfig
}

func NewConfigBuilder() *ConfigBuilder {
	return &ConfigBuilder{
		config: DatabaseConfig{
			Port:    5432,
			Timeout: 30,
		},
	}
}

func (b *ConfigBuilder) SetHost(host string) *ConfigBuilder {
	b.config.Host = host
	return b
}

func (b *ConfigBuilder) SetPort(port int) *ConfigBuilder {
	b.config.Port = port
	return b
}

func (b *ConfigBuilder) SetDatabase(database string) *ConfigBuilder {
	b.config.Database = database
	return b
}

func (b *ConfigBuilder) SetCredentials(username, password string) *ConfigBuilder {
	b.config.Username = username
	b.config.Password = password
	return b
}

func (b *ConfigBuilder) EnableSSL(enable bool) *ConfigBuilder {
	b.config.SSL = enable
	return b
}

func (b *ConfigBuilder) SetTimeout(timeout int) *ConfigBuilder {
	b.config.Timeout = timeout
	return b
}

func (b *ConfigBuilder) Build() (DatabaseConfig, error) {
	if b.config.Host == "" {
		return DatabaseConfig{}, fmt.Errorf("host is required")
	}
	if b.config.Database == "" {
		return DatabaseConfig{}, fmt.Errorf("database name is required")
	}
	return b.config, nil
}

func (c DatabaseConfig) String() string {
	var sb strings.Builder
	sb.WriteString(fmt.Sprintf("host=%s port=%d db=%s ssl=%v timeout=%d",
		c.Host, c.Port, c.Database, c.SSL, c.Timeout))
	return sb.String()
}

func main() {
	config, err := NewConfigBuilder().
		SetHost("localhost").
		SetPort(5432).
		SetDatabase("myapp").
		SetCredentials("user", "pass").
		EnableSSL(true).
		Build()

	if err != nil {
		panic(err)
	}

	fmt.Printf("Config: %s\n", config)
}

package composition

import "fmt"

type Engine interface {
	Start()
	Stop()
	GetPower() int
}

type ElectricEngine struct {
	power int
}

func (e *ElectricEngine) Start() {
	fmt.Println("Electric engine started")
}

func (e *ElectricEngine) Stop() {
	fmt.Println("Electric engine stopped")
}

func (e *ElectricEngine) GetPower() int {
	return e.power
}

type GasolineEngine struct {
	power int
}

func (g *GasolineEngine) Start() {
	fmt.Println("Gasoline engine started")
}

func (g *GasolineEngine) Stop() {
	fmt.Println("Gasoline engine stopped")
}

func (g *GasolineEngine) GetPower() int {
	return g.power
}

type Vehicle struct {
	name   string
	engine Engine
	wheels int
}

func NewVehicle(name string, engine Engine, wheels int) *Vehicle {
	return &Vehicle{
		name:   name,
		engine: engine,
		wheels: wheels,
	}
}

func (v *Vehicle) Start() {
	fmt.Printf("Starting %s...\n", v.name)
	v.engine.Start()
}

func (v *Vehicle) Stop() {
	fmt.Printf("Stopping %s...\n", v.name)
	v.engine.Stop()
}

func (v *Vehicle) Describe() string {
	return fmt.Sprintf("%s with %d wheels and %d HP engine",
		v.name, v.wheels, v.engine.GetPower())
}

func main() {
	eleCar := NewVehicle("Tesla Model 3", &ElectricEngine{power: 300}, 4)
	eleCar.Start()
	fmt.Println(eleCar.Describe())
	eleCar.Stop()

	fmt.Println()

	gasCar := NewVehicle("Toyota Camry", &GasolineEngine{power: 200}, 4)
	gasCar.Start()
	fmt.Println(gasCar.Describe())
	gasCar.Stop()
}
